import{_ as e,o as i,c as t,a2 as l}from"./chunks/framework.Cr-Z7ngm.js";const p=JSON.parse('{"title":"生物认证","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/biometric-auth.md","filePath":"zh-CN/account/biometric-auth.md"}'),r={name:"account/biometric-auth.md"};function o(h,a,n,c,d,u){return i(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="生物认证" tabindex="-1">生物认证 <a class="header-anchor" href="#生物认证" aria-label="Permalink to &quot;生物认证&quot;">​</a></h1><p>生物认证服务是长桥提供的身份认证功能，使用指纹或面部识别等生物特征代替安全编码（交易密码）验证身份，用于发出交易指示和授权操作。</p><h2 id="启动与取消" tabindex="-1">启动与取消 <a class="header-anchor" href="#启动与取消" aria-label="Permalink to &quot;启动与取消&quot;">​</a></h2><h3 id="启动" tabindex="-1">启动 <a class="header-anchor" href="#启动" aria-label="Permalink to &quot;启动&quot;">​</a></h3><p>在认可移动设备（iOS 或 Android）上启动生物认证传感器，并按照 App 指引完成注册。注册成功后可在 App 中使用生物认证凭证代替安全编码。</p><p>启动后仍可选择使用安全编码发出指示。</p><h3 id="取消" tabindex="-1">取消 <a class="header-anchor" href="#取消" aria-label="Permalink to &quot;取消&quot;">​</a></h3><p>可随时在 App 中取消生物认证服务，取消后继续使用安全编码操作。</p><h3 id="重新启动" tabindex="-1">重新启动 <a class="header-anchor" href="#重新启动" aria-label="Permalink to &quot;重新启动&quot;">​</a></h3><p>以下情况需重新启动生物认证服务：</p><ul><li>使用新的移动设备</li><li>重新安装 App 或删除本地数据</li></ul><h2 id="安全须知" tabindex="-1">安全须知 <a class="header-anchor" href="#安全须知" aria-label="Permalink to &quot;安全须知&quot;">​</a></h2><ul><li>确保认可移动设备只储存本人的生物识别凭据。如存储他人生物认证凭证，您需对所有由此产生的指示和交易负责</li><li>不得在已越狱（jailbroken）或已开放根目录权限（rooted）的设备上使用生物认证服务</li><li>如有双胞胎兄弟姐妹或处于青春期（面部特征快速发育），建议使用安全编码</li><li>避免停用可能影响生物认证安全性的功能（如面部识别的注视感知功能）</li><li>如知悉或怀疑生物认证遭未经授权使用，请尽快联系长桥客服</li></ul><h2 id="重要说明" tabindex="-1">重要说明 <a class="header-anchor" href="#重要说明" aria-label="Permalink to &quot;重要说明&quot;">​</a></h2><ul><li>长桥不会存储您的生物认证凭证</li><li>生物认证传感器由设备制造商提供，长桥不对传感器技术负责</li><li>通过生物认证发出的所有指示对您具有约束力</li><li>长桥有权随时修改、暂停或终止生物认证服务</li></ul>',15)])])}const _=e(r,[["render",o]]);export{p as __pageData,_ as default};
